const parsed = $('FN - Parseia Resposta').first().json;
const fatura = $input.first().json;
const fatura_id = fatura.id;
const usuario_id = parsed.usuario_id;
const lancamentos = parsed.lancamentos || [];

if (!fatura_id) {
  return [{ json: { error: true, message: 'fatura_id não retornado pelo INSERT' } }];
}

const itens = lancamentos.map(l => ({
  fatura_id: fatura_id,
  usuario_id: usuario_id,
  data_lancamento: l.data_lancamento || null,
  descricao: l.descricao || '',
  estabelecimento: (l.estabelecimento || l.descricao || '').substring(0, 200),
  valor: Number(l.valor) || 0,
  tipo: l.tipo === 'credito' ? 'credito' : 'debito',
  parcela_atual: l.parcela_atual ? Number(l.parcela_atual) : null,
  parcela_total: l.parcela_total ? Number(l.parcela_total) : null
}));

return itens.map(item => ({ json: item }));

